body: "Test Syntaxhighliter PyBlosxom 関係ではないが、SyntaxHighlighter を入れてみて。 #! /usr/bin/env python import sys import re import poplib, email from email import Header host = \u0026#39;localhost\u0026#39; port = \u0026#39;PORT\u0026#39; account = \u0026#39;MAIL-ADDRESS\u0026#39; password = \u0026#39;PASSWORD\u0026#39; s = poplib.POP3 (host, port) s.apop (account, password) n = len (s.list ()[1]) # X-Spambayes-MailId: 1238488913 for i in range (n): l = s.retr (i+1)[1] msg = email.message_from_string (\u0026#39;\\n\u0026#39;.join (l)) subject = Header.decode_header (msg.get (\u0026#39;subject\u0026#39;))[0][0] dtispamsign = Header.decode_header (msg.get (\u0026#39;x-dti-spam-flag\u0026#39;))[0][0] spamsign = Header.decode_header (msg.get (\u0026#39;x-spam-flag\u0026#39;))[0][0] mailid = Header.decode_header (msg.get (\u0026#39;x-spam-probability\u0026#39;))[0][0] if dtispamsign == \u0026#39;Yes\u0026#39;: print \u0026#39;\u0026lt;D\u0026gt;\u0026#39;, i+1, spamsign, dtispamsign, subject s.dele(i+1) elif spamsign == \u0026#39;Yes\u0026#39;: print \u0026#39;\u0026lt;D\u0026gt;\u0026#39;, i+1, spamsign, dtispamsign, subject s.dele(i+1) else: print \u0026#39; \u0026#39;, i+1, spamsign, dtispamsign, subject s.quit ()"
